// n8n Code Node v3 — format laporan harian untuk Telegram
// Includes _debug info and error details

function fmt(n) {
  const num = Number(n) || 0;
  return 'Rp ' + num.toLocaleString('id-ID');
}

// Ambil item pertama dari input
const items = $input.all();
const raw = items[0]?.json || {};

// Jika API error atau response kosong
if (!raw || Object.keys(raw).length === 0) {
  return [{ json: { message: '⚠️ API returned empty response' } }];
}

if (raw.success === false) {
  const debugInfo = raw._debug ? '\n\n🔍 DEBUG:\n' + JSON.stringify(raw._debug, null, 2) : '';
  const errMsg = raw.error || 'Unknown';
  const stack = raw.stack ? '\n' + raw.stack.join('\n') : '';
  return [{ json: { message: '⚠️ API Error: ' + errMsg + stack + debugInfo } }];
}

// Extract data — handle both {success,data} wrapper and direct data
const d = raw.data || raw;
const s = d.summary || {};
const c = d.comparison || {};
const platforms = Array.isArray(d.platforms) ? d.platforms : [];
const aging = d.aging || { total: 0, detail: {} };
const debug = raw._debug || d._debug || {};

// Platform lines
let platformLines = '├ Tidak ada data platform';
if (platforms.length > 0) {
  platformLines = platforms.map(function(p) {
    return '├ ' + (p.platform || 'Unknown') + ' : ' + fmt(p.omzet) + ' (' + (p.count || 0) + ' order)';
  }).join('\n');
}

// Aging backlog
const agingDetail = aging.detail || {};
let agingStr = '├ Tidak ada';
const agingKeys = Object.keys(agingDetail);
if (agingKeys.length > 0) {
  agingStr = agingKeys.map(function(k) {
    return '├ ' + k + ': ' + agingDetail[k];
  }).join('\n');
}

// Tanggal
const dateStr = d.date || new Date().toISOString().slice(0, 10);
let tgl = dateStr;
try {
  tgl = new Date(dateStr + 'T00:00:00+07:00').toLocaleDateString('id-ID', {
    weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
  });
} catch(e) { /* fallback to dateStr */ }

const omzet = Number(s.omzet) || 0;
const hpp = Number(s.hpp) || 0;
const gp = Number(s.grossProfit) || 0;
const margin = omzet > 0 ? ((gp / omzet) * 100).toFixed(1) : '0';

// Comparison
const prevOmzet = Number(c.prevOmzet) || 0;
const omzetDiff = Number(c.omzetDiff) || 0;
const orderDiff = Number(c.orderCountDiff) || 0;
const omzetArrow = omzetDiff >= 0 ? '↑' : '↓';
const orderArrow = orderDiff >= 0 ? '↑' : '↓';
const omzetComp = prevOmzet > 0 ? omzetArrow + ' ' + fmt(Math.abs(omzetDiff)) : '—';
const orderComp = orderArrow + ' ' + Math.abs(orderDiff) + ' order';

// Debug line (only if debug data exists)
let debugLine = '';
if (debug.dateFrom) {
  debugLine = '\n\n🔍 DEBUG: ' + debug.dateFrom + ' | rows: ' + (debug.todayOrderRows || 0) + ' | gte: ' + (debug.gteDate || '') + ' | lte: ' + (debug.lteDate || '');
}

const msg = `📊 LAPORAN HARIAN ELYASR
${tgl} — 17.30 WIB

💰 OMZET & PROFIT (Hari Ini)
├ Real Omzet    : ${fmt(omzet)}
├ HPP Total     : ${fmt(hpp)}
└ Gross Profit  : ${fmt(gp)} (${margin}%)

📦 ORDER
├ Total Masuk  : ${s.totalOrder || 0} order
├ Terkirim     : ${s.terkirim || 0} order
├ Pending Kirim: ${s.perluKirim || 0} order
└ Dibatalkan   : ${s.batal || 0} order

🏪 PER PLATFORM
${platformLines}

😡 AGING BACKLOG (${aging.total || 0} order pending)
${agingStr}

🔥 STOK KRITIS: ${d.stokKritis || 0} SKU perlu restock

📈 VS KEMARIN
├ Omzet  : ${omzetComp}
└ Order  : ${orderComp}${debugLine}

This message was sent automatically with n8n`;

return [{ json: { message: msg } }];
